340→    /**
341→     * This method generates a note from a sample model, or fails if invalid
342→     * @param cardIndex The index in the templates for the model. NOT `ord`
343→     */
344→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
345→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
346→        if (notetype == null) {
347→            return null
348→        }
349→        if (mAllFieldsNull) {
350→            getLabels(fieldValues)
351→        }
352→        val n = getColUnsafe.newNote(notetype)
353→        var i = 0
354→        while (i < fieldValues.size && i < n.fields.size) {
355→            if (mAllFieldsNull) {
356→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
357→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
358→                ) {
359→                    n.setField(i, fieldValues[i])
360→                } else {
361→                    n.setField(i, "(" + fieldValues[i] + ")")
362→                }
363→            } else {
364→                n.setField(i, fieldValues[i])
365→            }
366→            i++
367→        }
368→        try {
369→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
370→        } catch (e: Exception) {
371→            // Calling code handles null return, so we can log this for developer's interest but move on
372→            Timber.d(e, "getDummyCard() unable to create card")
373→        }
374→        return null
375→    }
