326→    /**
327→     * Converts the card's `ord` (ordinal) to the `cardIndex` used for preview navigation.
328→     * For standard note types, ord equals cardIndex.
329→     * For cloze note types, the index is determined by the position in clozeNumbersInNote.
330→     * @param col The collection
331→     * @param ordinal The card's ord value
332→     * @return The card index for preview, or 0 if not found
333→     */
334→    private fun getCardIndexFromOrdinal(col: Collection, ordinal: Int): Int {
335→        if (mEditedNotetype == null) {
336→            return ordinal
337→        }
338→        return if (mEditedNotetype!!.isCloze) {
339→            val note = col.newNote(mEditedNotetype!!)
340→            val fieldValues = getBundleEditFields(mNoteEditorBundle)
341→            for (i in fieldValues.indices) {
342→                if (i < note.fields.size) {
343→                    note.setField(i, fieldValues[i])
344→                }
345→            }
346→            val clozeNumbers = col.clozeNumbersInNote(note)
347→            // ordinal is 0-indexed, clozeNumbers are 1-indexed (c1 -> 1, c2 -> 2, etc.)
348→            val index = clozeNumbers.indexOf(ordinal + 1)
349→            if (index >= 0) index else 0
350→        } else {
351→            ordinal
352→        }
353→    }
