364→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
365→        val noteFields = noteEditorBundle!!.getBundle("editFields")
366→            ?: return mutableListOf()
367→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
368→        // so convert this to a list of strings, with null in place of the invalid fields
369→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
