266→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
267→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
268→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
269→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
270→                if (currentCard == null) {
271→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
272→                    closeCardTemplatePreviewer()
273→                }
274→            }
275→        }
276→        if (currentCard == null) {
277→            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
278→            closeCardTemplatePreviewer()
279→            return
280→        }
281→        displayCardQuestion()
282→        if (mShowingAnswer) {
283→            displayCardAnswer()
284→        }
285→        showBackIcon()
286→    }
