292→    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
293→        assert(mNoteEditorBundle != null)
294→        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
295→        // example: a basic card with no fields provided
296→        if (currentCard == null) {
297→            return null
298→        }
299→        val newDid = mNoteEditorBundle!!.getLong("did")
300→        if (col.decks.isDyn(newDid)) {
301→            currentCard!!.oDid = currentCard!!.did
302→        }
303→        currentCard!!.did = newDid
304→        val currentNote = currentCard!!.note()
305→        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
306→        setTags(currentNote, tagsList)
307→        return currentCard
308→    }
