310→    /**
311→     * Set the set tags of currentNote to tagsList.  We make no
312→     * assumption on the content of tagsList, except that its strings
313→     * are valid tags (i.e. no spaces in it).
314→     */
315→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
316→        val currentTags = currentNote.tags.toTypedArray()
317→        for (tag in currentTags) {
318→            currentNote.delTag(tag)
319→        }
320→        if (tagsList != null) {
321→            val tagsSet = currentNote.col.tags.canonify(tagsList)
322→            currentNote.addTags(tagsSet)
323→        }
324→    }
