385→    /**
386→     * This method generates a note from a sample model, or fails if invalid
387→     * @param cardIndex The index in the templates for the model. NOT `ord`
388→     */
389→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
390→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
391→        if (notetype == null) {
392→            return null
393→        }
394→        if (mAllFieldsNull) {
395→            getLabels(fieldValues)
396→        }
397→        val n = getColUnsafe.newNote(notetype)
398→        var i = 0
399→        while (i < fieldValues.size && i < n.fields.size) {
400→            if (mAllFieldsNull) {
401→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
402→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
403→                ) {
404→                    n.setField(i, fieldValues[i])
405→                } else {
406→                    n.setField(i, "(" + fieldValues[i] + ")")
407→                }
408→            } else {
409→                n.setField(i, fieldValues[i])
410→            }
411→            i++
412→        }
413→        try {
414→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
415→        } catch (e: Exception) {
416→            // Calling code handles null return, so we can log this for developer's interest but move on
417→            Timber.d(e, "getDummyCard() unable to create card")
418→        }
419→        return null
420→    }
