422→    /** Override certain aspects of Card behavior so we may display unsaved data  */
423→    inner class PreviewerCard : Card {
424→        private val mNote: Note?
425→
426→        constructor(col: Collection, id: Long) : super(col, id) {
427→            mNote = null
428→        }
429→
430→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
431→            reload: Boolean
432→        ): Note {
433→            return mNote ?: super.note(reload)
434→        }
435→
436→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
437→        override fun note(): Note {
438→            return mNote ?: super.note()
439→        }
440→
441→        /** if we have an unsaved note, never return empty  */
442→        val isEmpty: Boolean
443→            get() = mNote != null
444→
445→        /** Override the method that fetches the model so we can render unsaved models  */
446→        override fun model(): NotetypeJson {
447→            return mEditedNotetype ?: super.model()
448→        }
449→
450→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
451→            if (renderOutput == null || reload) {
452→                val index = if (model().isCloze) {
453→                    0
454→                } else {
455→                    ord
456→                }
457→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
458→                    note(),
459→                    this,
460→                    model(),
461→                    model().getJSONArray("tmpls")[index] as JSONObject,
462→                    fillEmpty = false
463→                )
464→                renderOutput =
465→                    context.render()
466→            }
467→            return renderOutput!!
468→        }
469→    }
470→}
471→
472→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
473→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
474→        return this.renderOutput!!
475→    }
476→    companion object {
477→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
478→            val card = EphemeralCard(col, null)
479→            card.did = 1
480→            card.ord = n.cardIndexToOrd(cardIndex)
481→
482→            val nt = n.notetype
483→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
484→                0
485→            } else {
486→                cardIndex
487→            }
488→            val template = nt.tmpls[templateIdx] as JSONObject
489→            template.put("ord", card.ord)
490→
491→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
492→                n,
493→                card,
494→                notetype = nt,
495→                template = template,
496→                fillEmpty = false
497→            ).render()
498→            card.renderOutput = output
499→            card.setNote(n)
500→            return card
501→        }
502→    }
503→}
