505→/** returns the number of cards from a note which has not had data saved in the database */
506→private fun Note.numberOfCardsEphemeral(): Int {
507→    // We can't use note.numberOfCards() as this uses the database value
508→    return when {
509→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
510→        else -> notetype.templatesNames.size
511→    }
512→}
