514→/**
515→ * Given a card index, returns the 'ord' of the card
516→ */
517→private fun Note.cardIndexToOrd(index: Int): Int {
518→    // We can't use note.numberOfCards() as this uses the database value
519→    return when {
520→        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
521→        else -> index
522→    }
523→}
